func NewSummaryValue(attributeTypes map[string]attr.Type, attributes map[string]attr.Value) (SummaryValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	// Reference: https://github.com/hashicorp/terraform-plugin-framework/issues/521
	ctx := context.Background()

	for name, attributeType := range attributeTypes {
		attribute, ok := attributes[name]

		if !ok {
			diags.AddError(
				"Missing SummaryValue Attribute Value",
				"While creating a SummaryValue value, a missing attribute value was detected. "+
					"A SummaryValue must contain values for all attributes, even if null or unknown. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("SummaryValue Attribute Name (%s) Expected Type: %s", name, attributeType.String()),
			)

			continue
		}

		if !attributeType.Equal(attribute.Type(ctx)) {
			diags.AddError(
				"Invalid SummaryValue Attribute Type",
				"While creating a SummaryValue value, an invalid attribute value was detected. "+
					"A SummaryValue must use a matching attribute type for the value. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("SummaryValue Attribute Name (%s) Expected Type: %s\n", name, attributeType.String())+
					fmt.Sprintf("SummaryValue Attribute Name (%s) Given Type: %s", name, attribute.Type(ctx)),
			)
		}
	}

	for name := range attributes {
		_, ok := attributeTypes[name]

		if !ok {
			diags.AddError(
				"Extra SummaryValue Attribute Value",
				"While creating a SummaryValue value, an extra attribute value was detected. "+
					"A SummaryValue must not contain values beyond the expected attribute types. "+
					"This is always an issue with the provider and should be reported to the provider developers.\n\n"+
					fmt.Sprintf("Extra SummaryValue Attribute Name: %s", name),
			)
		}
	}

	if diags.HasError() {
		return NewSummaryValueUnknown(), diags
	}

	operationalRisksAttribute, ok := attributes["operational_risks"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`operational_risks is missing from object`)

		return NewSummaryValueUnknown(), diags
	}

	operationalRisksVal, ok := operationalRisksAttribute.(basetypes.Float64Value)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`operational_risks expected to be basetypes.Float64Value, was: %T`, operationalRisksAttribute))
	}

	performanceRisksAttribute, ok := attributes["performance_risks"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`performance_risks is missing from object`)

		return NewSummaryValueUnknown(), diags
	}

	performanceRisksVal, ok := performanceRisksAttribute.(basetypes.Float64Value)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`performance_risks expected to be basetypes.Float64Value, was: %T`, performanceRisksAttribute))
	}

	potentialDailySavingsAttribute, ok := attributes["potential_daily_savings"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`potential_daily_savings is missing from object`)

		return NewSummaryValueUnknown(), diags
	}

	potentialDailySavingsVal, ok := potentialDailySavingsAttribute.(basetypes.Float64Value)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`potential_daily_savings expected to be basetypes.Float64Value, was: %T`, potentialDailySavingsAttribute))
	}

	reliabilityRisksAttribute, ok := attributes["reliability_risks"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`reliability_risks is missing from object`)

		return NewSummaryValueUnknown(), diags
	}

	reliabilityRisksVal, ok := reliabilityRisksAttribute.(basetypes.Float64Value)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`reliability_risks expected to be basetypes.Float64Value, was: %T`, reliabilityRisksAttribute))
	}

	securityRisksAttribute, ok := attributes["security_risks"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`security_risks is missing from object`)

		return NewSummaryValueUnknown(), diags
	}

	securityRisksVal, ok := securityRisksAttribute.(basetypes.Float64Value)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`security_risks expected to be basetypes.Float64Value, was: %T`, securityRisksAttribute))
	}

	sustainabilityRisksAttribute, ok := attributes["sustainability_risks"]

	if !ok {
		diags.AddError(
			"Attribute Missing",
			`sustainability_risks is missing from object`)

		return NewSummaryValueUnknown(), diags
	}

	sustainabilityRisksVal, ok := sustainabilityRisksAttribute.(basetypes.Float64Value)

	if !ok {
		diags.AddError(
			"Attribute Wrong Type",
			fmt.Sprintf(`sustainability_risks expected to be basetypes.Float64Value, was: %T`, sustainabilityRisksAttribute))
	}

	if diags.HasError() {
		return NewSummaryValueUnknown(), diags
	}

	return SummaryValue{
		OperationalRisks:      operationalRisksVal,
		PerformanceRisks:      performanceRisksVal,
		PotentialDailySavings: potentialDailySavingsVal,
		ReliabilityRisks:      reliabilityRisksVal,
		SecurityRisks:         securityRisksVal,
		SustainabilityRisks:   sustainabilityRisksVal,
		state:                 attr.ValueStateKnown,
	}, diags
}

func NewSummaryValueMust(attributeTypes map[string]attr.Type, attributes map[string]attr.Value) SummaryValue {
	object, diags := NewSummaryValue(attributeTypes, attributes)

	if diags.HasError() {
		// This could potentially be added to the diag package.
		diagsStrings := make([]string, 0, len(diags))

		for _, diagnostic := range diags {
			diagsStrings = append(diagsStrings, fmt.Sprintf(
				"%s | %s | %s",
				diagnostic.Severity(),
				diagnostic.Summary(),
				diagnostic.Detail()))
		}

		panic("NewSummaryValueMust received error(s): " + strings.Join(diagsStrings, "\n"))
	}

	return object
}

func (t SummaryType) ValueFromTerraform(ctx context.Context, in tftypes.Value) (attr.Value, error) {
	if in.Type() == nil {
		return NewSummaryValueNull(), nil
	}

	if !in.Type().Equal(t.TerraformType(ctx)) {
		return nil, fmt.Errorf("expected %s, got %s", t.TerraformType(ctx), in.Type())
	}

	if !in.IsKnown() {
		return NewSummaryValueUnknown(), nil
	}

	if in.IsNull() {
		return NewSummaryValueNull(), nil
	}

	attributes := map[string]attr.Value{}

	val := map[string]tftypes.Value{}

	err := in.As(&val)

	if err != nil {
		return nil, err
	}

	for k, v := range val {
		a, err := t.AttrTypes[k].ValueFromTerraform(ctx, v)

		if err != nil {
			return nil, err
		}

		attributes[k] = a
	}

	return NewSummaryValueMust(SummaryValue{}.AttributeTypes(ctx), attributes), nil
}

